class Solution {
    public String lastSubstring(String s) {
        int n = s.length();
        int[] suffixArray = new int[n];
        for (int i = 0; i < n; i++) {
            suffixArray[i] = i;
        }
        Arrays.sort(suffixArray, (a, b) -> {
            int i = 0;
            while (a + i < n && b + i < n && s.charAt(a + i) == s.charAt(b + i)) {
                i++;
            }
            if (a + i == n) return -1;
            if (b + i == n) return 1;
            return Character.compare(s.charAt(a + i), s.charAt(b + i));
        });
        return s.substring(suffixArray[n - 1]);
    }
}
